export const getFormattedPointsValue = (
  amount: number,
  type: TransactionType,
): string => {
  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
};
```

**VERIFIED: CORRECT** - The sign handling is correct:
- `CREDIT` and `REFUNDED` types display with `+` prefix
- `RESCUE` and `EXPIRED` types display with `-` prefix
- `Math.abs()` is appropriately used here because the sign is handled by the prefix

